const trigger = $('When chat message received3').first().json;
const rows = $input.all();

let prev = {
  history: [],
  last_user_msg: '',
  last_intent: '',
  last_brand: '',
  last_model: '',
  last_ai_reply: ''
};

if (rows.length && rows[0].json && rows[0].json.sessionId) {
  const r = rows[0].json;
  let history = [];
  try {
    history = r.history_json ? JSON.parse(r.history_json) : [];
    if (!Array.isArray(history)) history = [];
  } catch(e) { history = []; }

  prev = {
    history,
    last_user_msg: r.last_user_msg || '',
    last_intent:   r.last_intent   || '',
    last_brand:    r.last_brand    || '',
    last_model:    r.last_model    || '',
    last_ai_reply: r.last_ai_reply || ''
  };
}

return [{ json: { ...trigger, _prev: prev } }];

// capture_reply (cập nhật)
const item = $input.first().json;
const reply = item.output || item.text || item.response || '';

return [{
  json: {
    output: reply,
    _ai_reply_short: reply.slice(-300)
  }
}];

const router = $input.first().json;
const trigger = $('When chat message received3').first().json;

// Lấy chatInput từ nhiều nguồn fallback
const userMsg =
  trigger.chatInput ||
  trigger.body?.message?.text ||                                    // Webhook raw
  $('Webhook').first().json?.body?.message?.text ||                 // nếu node tên khác
  '';

const sessionId = trigger.sessionId || trigger.body?.conversation?.id || 'default';
const prevHistory = ($('parse_session').first().json._prev?.history) || [];

const newTurn = {
  ts: new Date().toISOString().slice(0, 19),
  user: userMsg.slice(0, 150),
  intent: router.category || '',
  brand: router.brand || '',
  model: router.model_slug || ''
};

const newHistory = [...prevHistory, newTurn].slice(-10);

return [{
  json: {
    ...router,
    sessionId,
    last_user_msg: newTurn.user,
    last_intent: newTurn.intent,
    last_brand: newTurn.brand,
    last_model: newTurn.model,
    history_json: JSON.stringify(newHistory)
  }
}];

// Static reply pool — random pick để tránh trả y hệt mỗi lần
const replies = [
  "Dạ em chỉ hỗ trợ tư vấn xe THACO AUTO (Kia, Mazda, Peugeot, BMW, MINI, xe tải/bus). Anh/Chị có câu hỏi nào về xe không ạ? Em hỗ trợ ngay!",

  "Dạ em xin phép — em là trợ lý tư vấn của THACO AUTO nên chỉ hỗ trợ các câu hỏi liên quan đến xe ạ. Em có thể giúp Anh/Chị: tìm xe phù hợp ngân sách, báo giá, tìm showroom gần nhất, hoặc tư vấn lái thử.",

  "Dạ chủ đề này hơi ngoài phạm vi hỗ trợ của em rồi ạ. Em chuyên về xe Kia/Mazda/Peugeot/BMW/MINI — Anh/Chị đang quan tâm dòng nào hoặc tầm giá khoảng bao nhiêu ạ?"
];

const pick = replies[Math.floor(Math.random() * replies.length)];
return [{ json: { output: pick } }];

// merge_lead_state — Code node sau "AI Agent — Test Drive Extractor"
// Parse JSON output → merge với state cũ → check completeness
// Bonus: nếu thiếu showroom + có user_location → geocode + suggest top 3 nearest

const aiRaw = $input.first().json.output || '';
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';
const FALLBACK_URL = 'https://thacoautotphcm.vn/showrooms';
const MAX_DISTANCE_KM = 150;

// 1. Parse extractor JSON
let extracted = {};
try {
  const m = aiRaw.match(/\{[\s\S]*\}/);
  if (m) extracted = JSON.parse(m[0]);
} catch (e) {}

// 2. Load prior state
let prior = {};
try {
  const row = $('gs_read_lead_state').first().json;
  if (row && row.lead_partial_json) {
    prior = JSON.parse(row.lead_partial_json);
  }
} catch (e) {}

function isValidVnPhone(p) {
  if (!p) return false;
  const cleaned = p.toString().replace(/[\s\-\.]/g, '');
  return /^(\+84|84|0)[0-9]{9,10}$/.test(cleaned);
}

// 3. Merge
const merged = {
  name: extracted.name || prior.name || null,
  phone: extracted.phone || prior.phone || null,
  model_interest: extracted.model_interest || prior.model_interest || null,
  showroom: extracted.showroom || prior.showroom || null,
  preferred_datetime: extracted.preferred_datetime || prior.preferred_datetime || null
};

// user_location KHÔNG persist (chỉ dùng để gợi ý showroom turn này)
const user_location = (extracted.user_location || '').trim();

if (merged.phone && !isValidVnPhone(merged.phone)) {
  merged.phone = null;
}

const missing = Object.entries(merged)
  .filter(([k, v]) => !v)
  .map(([k]) => k);
const isComplete = missing.length === 0;

const sessionId = $('Webhook').first().json.sessionId || 'default';

// =========================================================
// BONUS: nếu thiếu showroom + có user_location → suggest
// =========================================================
let showroom_suggestions = [];
let suggestion_text = '';

function inferBrandFromModel(modelText) {
  const t = (modelText || '').toLowerCase();
  if (/\b(sportage|carnival|carens|seltos|sorento|sonet|k3|k5|morning|new\s*carnival)\b/.test(t)) return 'kia';
  if (/\b(mazda|cx-?\d+|mx-?\d+|cx5|cx3|cx30|cx8|mazda3|mazda6|mazda2)\b/.test(t)) return 'mazda';
  if (/\b(peugeot|3008|5008|2008|408|traveller)\b/.test(t)) return 'peugeot';
  if (/\b(bmw|x[1-7]\b|series|3 ?series|5 ?series|7 ?series|i[345789]\b|330|320|520|530|730)\b/.test(t)) return 'bmw';
  if (/\b(mini|cooper|countryman|clubman)\b/.test(t)) return 'mini';
  return '';
}

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const toRad = x => x * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon/2)**2;
  return 2 * R * Math.asin(Math.sqrt(a));
}


const PASSENGER_BRANDS = ['kia', 'mazda', 'peugeot', 'bmw', 'mini'];
function brandMatches(showroom, b) {
  if (!b) return true;
  const slugs = showroom.brand_slugs || [];
  // Exact match — KHÔNG dùng includes() vì 'kia-frontier'.includes('kia') sẽ kéo nhầm xe tải
  if (!slugs.includes(b)) return false;
  // Brand xe du lịch → chỉ lấy showroom oto, loại tai/bus
  if (PASSENGER_BRANDS.includes(b) && showroom.type_showroom && showroom.type_showroom !== 'oto') return false;
  return true;
}

if (!merged.showroom && user_location) {
  try {
    // Geocode user location
    const geo = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nominatim.openstreetmap.org/search',
      qs: { format: 'json', q: /vietnam|việt nam/i.test(user_location) ? user_location : (user_location + ', Việt Nam'), limit: 1 },
      headers: { 'User-Agent': 'thacoauto-chatbot/1.0 (contact: phogotarot@gmail.com)' },
      json: true,
      returnFullResponse: false
    });
    const arr = (typeof geo === 'string') ? JSON.parse(geo) : geo;

    if (Array.isArray(arr) && arr.length) {
      const ulat = parseFloat(arr[0].lat);
      const ulon = parseFloat(arr[0].lon);

      // Load catalog
      const cat = await this.helpers.httpRequest({
        method: 'GET',
        url: base + 'wiki/dealers/catalog.json',
        json: true,
        returnFullResponse: false
      });
      const data = (typeof cat === 'string') ? JSON.parse(cat) : cat;

      // Filter brand từ model_interest
      const inferredBrand = inferBrandFromModel(merged.model_interest || '');
      let candidates = (data.showrooms || []).filter(s =>
        typeof s.lat === 'number' && typeof s.lon === 'number'
      );
      if (inferredBrand) {
        const filtered = candidates.filter(s => brandMatches(s, inferredBrand));
        if (filtered.length) candidates = filtered;
      }

      const ranked = candidates
        .map(s => ({
          title: s.title,
          brand: (s.brands || []).join(', '),
          ward: s.address?.ward || '',
          street: s.address?.street || '',
          phone: s.phone_sale || '—',
          distance_km: haversineKm(ulat, ulon, s.lat, s.lon)
        }))
        .sort((a, b) => a.distance_km - b.distance_km)
        .slice(0, 3);

      if (ranked.length && ranked[0].distance_km > MAX_DISTANCE_KM) {
        // Quá xa → không gợi ý, báo cho AI biết
        showroom_suggestions = [];
        suggestion_text = `[KHÔNG có showroom phù hợp gần "${user_location}" — gần nhất cũng cách ~${ranked[0].distance_km.toFixed(0)}km. Dữ liệu hiện chỉ phủ cụm HCM và lân cận. Gợi ý cho AI: xin lỗi khách, KHÔNG ép khách chọn showroom xa, mời khách xem danh sách toàn quốc tại ${FALLBACK_URL} hoặc gọi 1900 545 591 để chuyên viên tư vấn showroom gần khách.]`;
      } else {
        showroom_suggestions = ranked;
        if (ranked.length) {
          suggestion_text = `Top ${ranked.length} showroom${inferredBrand ? ' ' + inferredBrand.toUpperCase() : ''} gần "${user_location}":\n` +
            ranked.map((s, i) => `  ${i+1}. ${s.title} — cách ~${s.distance_km.toFixed(1)}km — ${s.street}, P.${s.ward} — ${s.phone}`).join('\n');
        }
      }
    }
  } catch (e) {
    suggestion_text = `[Không truy vấn được showroom gần nhất: ${e.message}. Có thể gửi URL tra cứu: ${FALLBACK_URL}]`;
  }
}

return [{
  json: {
    sessionId,
    lead_data: merged,
    lead_partial_json: JSON.stringify(merged),
    missing_fields: missing,
    is_complete: isComplete,
    user_location,
    showroom_suggestions,
    suggestion_text,
    fallback_url: FALLBACK_URL,
    _debug_extracted: extracted,
    _debug_prior: prior
  }
}];

