} 
// 2. Nhóm xe lỗi / dịch vụ xưởng chậm chạp
else if (userMsg.match(/(hư|lỗi|hỏng|bảo hành|sửa|dịch vụ tệ|chậm|chất lượng|kêu|ồn|bảo dưỡng)/)) {
