// format_subiz_reply — chuẩn hoá output về JSON Subiz
const aiReply = $('capture_reply').first().json.output || '';

// Tách markdown link ảnh nếu có (vd: ![alt](https://...png))
const attachments = [];
const imgRegex = /https?:\/\/[^\s\)]+\.(png|jpg|jpeg|gif|webp)/gi;
const matches = [...aiReply.matchAll(imgRegex)];
for (const m of matches) {
  const ext = m[1].toLowerCase().replace('jpg', 'jpeg');
  attachments.push({
    type: 'file',
    mimetype: `image/${ext}`,
    url: m[0]
  });
}

// Loại URL ảnh khỏi text (tránh hiển thị 2 lần) — tuỳ chọn
const cleanText = aiReply.trim();

// Tách link non-image thành message thứ 2 (giống demo Subiz pricing)
const urlRegex = /(https?:\/\/[^\s]+)/g;
const urls = (cleanText.match(urlRegex) || [])
  .filter(u => !imgRegex.test(u));

const messages = [
  {
    format: 'plaintext',
    text: cleanText,
    ...(attachments.length ? { attachments } : {})
  }
];

// Nếu muốn tách link ra message riêng (Subiz render preview đẹp hơn):
// for (const u of urls) {
//   messages.push({ format: 'plaintext', text: u });
// }

return [{
  json: {
    messages
  }
}];
